import { Router } from 'express';
import { verifyRefreshToken, signAccessToken, signRefreshToken } from '../jwt';

export const refreshRouter = Router();

refreshRouter.post('/refresh', async (req, res) => {
  const { refreshToken } = req.body;
  if (!refreshToken) {
    return res.status(400).json({ error: 'refreshToken 不能为空' });
  }

  try {
    const payload = verifyRefreshToken(refreshToken);
    // 签发新 Token 对（轮换策略：旧的 Refresh Token 自动失效）
    const newAccess = signAccessToken({ userId: payload.userId, email: payload.email });
    const newRefresh = signRefreshToken({ userId: payload.userId, email: payload.email });
    res.json({ accessToken: newAccess, refreshToken: newRefresh });
  } catch {
    res.status(401).json({ error: 'Refresh Token 无效或已过期' });
  }
});

